import { useLocation } from 'react-router-dom';

function BreadCrumb() {
  const location = useLocation();
  // URL: /dashboard/settings?tab=security#password
  // location.pathname → '/dashboard/settings'
  // location.search   → '?tab=security'
  // location.hash     → '#password'
  // location.state    → dados passados via navigate/Link

  return <p>Você está em: {location.pathname}</p>;
}

import { useSearchParams } from 'react-router-dom';

function ProductList() {
  const [searchParams, setSearchParams] = useSearchParams();

  const category = searchParams.get('category') || 'all';
  const sort = searchParams.get('sort') || 'name';
  const page = Number(searchParams.get('page') || '1');

  // URL: /products?category=electronics&sort=price&page=2

  return (
    <div>
      {/* Filtro de categoria */}
      <select
        value={category}
        onChange={(e) => {
          searchParams.set('category', e.target.value);
          searchParams.set('page', '1');  // resetar paginação
          setSearchParams(searchParams);
        }}
      >
        <option value="all">Todas</option>
        <option value="electronics">Eletrônicos</option>
        <option value="clothing">Roupas</option>
      </select>

      {/* Paginação */}
      <button
        onClick={() => {
          searchParams.set('page', String(page + 1));
          setSearchParams(searchParams);
        }}
      >
        Próxima página
      </button>

      <p>Categoria: {category} | Ordenação: {sort} | Página: {page}</p>
    </div>
  );
}

import { useNavigate } from 'react-router-dom';

function CreateProductForm() {
  const navigate = useNavigate();

  const handleSubmit = async (data) => {
    const product = await createProduct(data);

    // Navegação para o produto criado
    navigate(`/products/${product.id}`);

    // Com replace (sem empilhar histórico)
    navigate('/products', { replace: true });

    // Com state (passar dados)
    navigate('/success', { state: { productName: product.name } });

    // Voltar
    navigate(-1);  // equivale ao botão 'voltar' do browser
  };
}

